style.img:
-embedded SVG's prefers-color-scheme follows the OS, not the
       docs' class-based theme toggle. Keep the two files' rules identical;
       ONLY the svg.root variable block below differs between them. */
    svg.root {
      --diagram-bg: #0a0a0a;
      --line: #e5e5e5;
      --ink:  #fafafa;
      --pos:  #4ade80;
      --neg:  #f87171;
      --flash: rgba(250, 250, 250, 0.45);
      --op-stroke-faded: 0.32;
      --op-band-bright:  0.70;
      --op-band-faded:   0.28;
      --op-connector:    0.55;
      --op-label-faded:  0.55;
      --op-label-mute:   0.40;
      --op-icon-faded:   0.60;
    }

    .bg-fill            { fill: var(--diagram-bg); }
    .stroke             { stroke: var(--line); fill: none; }
    .stroke-faded       { stroke: var(--line); opacity: var(--op-stroke-faded); fill: none; }
    .stroke-band-bright { stroke: var(--line); opacity: var(--op-band-bright); fill: none; }
    .stroke-band-faded  { stroke: var(--line); opacity: var(--op-band-faded); fill: none; }

    .label          { fill: var(--ink); font-family: ui-monospace, 'SF Mono', 'Geist Mono', Menlo, monospace; }
    .label-faded    { fill: var(--ink); opacity: var(--op-label-faded); font-family: ui-monospace, 'SF Mono', 'Geist Mono', Menlo, monospace; }
    .label-mute     { fill: var(--ink); opacity: var(--op-label-mute); font-family: ui-monospace, 'SF Mono', 'Geist Mono', Menlo, monospace; }
    .label-pos      { fill: var(--pos); font-family: ui-monospace, 'SF Mono', 'Geist Mono', Menlo, monospace; }
    .label-neg      { fill: var(--neg); font-family: ui-monospace, 'SF Mono', 'Geist Mono', Menlo, monospace; }
    .grid-dot       { fill: var(--ink); }
    .icon-fill      { fill: var(--line); }
    .icon-fill-faded { fill: var(--line); opacity: var(--op-icon-faded); }

    .connector-dotted {
      stroke: var(--line);
      stroke-width: 1;
      stroke-dasharray: 3 4;
      fill: none;
      opacity: var(--op-connector);
    }
    .reveal-mask {
      stroke: #fff;
      stroke-width: 4;
      fill: none;
      stroke-linecap: square;
    }

    .grid-layer { animation: fadeIn 500ms cubic-bezier(0.2, 0.8, 0.2, 1) 0ms both; }
    .corner-ticks {
      animation: drawIn 600ms cubic-bezier(0.2, 0.8, 0.2, 1) 0ms both;
      stroke-dasharray: 80; stroke-dashoffset: 80;
    }

    .layer-band-apps  { opacity: 0; animation: fadeInBandFaded 600ms cubic-bezier(0.2, 0.8, 0.2, 1) 200ms forwards; }
    .layer-band-trade { opacity: 0; animation: fadeInBandBright 600ms cubic-bezier(0.2, 0.8, 0.2, 1) 300ms forwards; }
    .layer-band-resolve { opacity: 0; animation: fadeInBandFaded 600ms cubic-bezier(0.2, 0.8, 0.2, 1) 400ms forwards; }

    .spine-question { opacity: 0; animation: fadeIn 500ms ease-out 600ms forwards; }
    .spine-resolve  { opacity: 0; animation: fadeIn 500ms ease-out 700ms forwards; }
    .app-side-left  { opacity: 0; animation: fadeInFaded 700ms ease-out 800ms forwards; }
    .app-side-right { opacity: 0; animation: fadeInFaded 700ms ease-out 900ms forwards; }

    .pool-box {
      opacity: 0;
      animation: fadeIn 700ms cubic-bezier(0.25, 0.7, 0.3, 1) 1000ms forwards;
    }
    .pool-content {
      opacity: 0;
      animation: fadeIn 500ms ease-out 1300ms forwards;
    }
    .pool-no-content {
      animation: fadeIn 500ms ease-out 1300ms forwards,
                 dimDown 800ms ease-out 8600ms forwards;
    }
    @keyframes dimDown { to { opacity: 0.32; } }

    /* Trunk + branches */
    .m-trunk      { --len: 85;  --dur: 500ms;  --delay: 1400ms; }
    .m-branch-yes { --len: 370; --dur: 900ms;  --delay: 1700ms; }
    .m-branch-no  { --len: 370; --dur: 900ms;  --delay: 1700ms; }
    .m-resolve    { --len: 130; --dur: 1500ms; --delay: 7300ms; }

    .reveal-mask {
      stroke-dasharray: var(--len);
      stroke-dashoffset: var(--len);
      animation: maskGrow var(--dur) cubic-bezier(0.4, 0.05, 0.2, 1) var(--delay) forwards;
    }

    /* Bet blips — short rows of dots that travel along the dotted
       connectors (using SMIL animateMotion + rotate="auto"). Multiple can
       be in flight at once, and each blip turns through the bend in the
       path so it actually follows the line into YES or NO. */
    .bet-yes .blip-bar > * { fill: var(--pos); }
    .bet-no  .blip-bar > * { fill: var(--neg); }

    /* Price stages — non-equal drops, settling at ¢40 to match the example.
       ¢48 → ¢45 → ¢43 → ¢41 → ¢40 (drops of 3, 2, 2, 1 — slowing as we
       approach the example's entry price). NO mirrors. */
    .price-stage { opacity: 0; }

    .yes-p1, .no-p1 { animation: priceShow 800ms ease-out 1500ms forwards, priceHide 350ms ease-in 3900ms forwards; }
    .yes-p2, .no-p2 { animation: priceShow 350ms ease-out 4000ms forwards, priceHide 350ms ease-in 4800ms forwards; }
    .yes-p3, .no-p3 { animation: priceShow 350ms ease-out 4900ms forwards, priceHide 350ms ease-in 5800ms forwards; }
    .yes-p4, .no-p4 { animation: priceShow 350ms ease-out 5900ms forwards, priceHide 350ms ease-in 6700ms forwards; }
    .yes-p5, .no-p5 { animation: priceShow 350ms ease-out 6800ms forwards, priceHide 400ms ease-in 8700ms forwards; }

    /* Settlement-stage values (the payout reveals) — fire AFTER the
       resolve-box price reveals so the order is: stop-flash → real price
       appears in the bottom box → payouts populate in the YES/NO pools. */
    .yes-payout, .no-payout { animation: priceShow 600ms ease-out 9200ms forwards; }

    /* Subtitles — start with condition, swap to math after the payout reveal */
    .yes-sub-cond, .no-sub-cond { animation: priceShow 800ms ease-out 1500ms forwards, priceHide 400ms ease-in 8700ms forwards; }
    .yes-sub-math, .no-sub-math { animation: priceShow 600ms ease-out 9400ms forwards; }

    /* Stop-flash — brief half-second pulse on the clock (top layer, right
       of the question) and on the bottom resolve box, indicating that
       the market has stopped trading. Fires alongside the existing settle
       sequence (pool dimming, center-fill, price hide). */
    .clock-flash, .settle-flash {
      fill: var(--flash);
      opacity: 0;
      pointer-events: none;
      animation: stopFlash 500ms cubic-bezier(0.4, 0, 0.6, 1) 8500ms forwards;
    }
    @keyframes stopFlash {
      0%   { opacity: 0; }
      20%  { opacity: 1; }
      45%  { opacity: 0.25; }
      70%  { opacity: 1; }
      100% { opacity: 0; }
    }

    /* Resolve-box price — starts as underscores (one per char of "$81,420")
       and swaps to the real settlement price right after the half-second
       flash ends. */
    .resolve-text-post { opacity: 0; animation: priceShow 350ms ease-out 9000ms forwards; }
    .resolve-text-pre  { animation: priceHide 350ms ease-in 9000ms forwards; }

    @keyframes priceShow { from { opacity: 0; transform: translateY(3px); } to { opacity: 1; transform: translateY(0); } }
    @keyframes priceHide { to { opacity: 0; transform: translateY(-3px); } }

    /* Settlement centerpiece — fires after the trading concludes */
    .center-edge {
      stroke: var(--line);
      stroke-width: 2;
      fill: none;
      stroke-dasharray: var(--len);
      stroke-dashoffset: var(--len);
      animation: maskGrow var(--dur) cubic-bezier(0.25, 0.46, 0.45, 0.94) var(--delay) forwards;
    }
    .center-edge-top-left  { --len: 120; --dur: 450ms;  --delay: 7400ms; }
    .center-edge-top-right { --len: 120; --dur: 450ms;  --delay: 7400ms; }
    .center-edge-left      { --len: 180; --dur: 650ms;  --delay: 7850ms; }
    .center-edge-right     { --len: 180; --dur: 650ms;  --delay: 7850ms; }
    .center-edge-bot-left  { --len: 120; --dur: 650ms;  --delay: 8500ms; }
    .center-edge-bot-right { --len: 120; --dur: 650ms;  --delay: 8500ms; }

    .center-fill {
      opacity: 0;
      animation: fadeIn 600ms cubic-bezier(0.22, 0.61, 0.36, 1) 8700ms forwards;
    }

    /* Improved settlement reveal: glow burst + scale-in label.
       Pushed to fire AFTER the resolve-box price reveals at 9000ms. */
    .center-glow {
      opacity: 0;
      transform-box: fill-box;
      transform-origin: center;
      animation: summonGlow 1400ms cubic-bezier(0.25, 0.46, 0.45, 0.94) 9100ms forwards;
    }

    .center-label {
      opacity: 0;
      transform-box: fill-box;
      transform-origin: center;
      animation: labelPop 700ms cubic-bezier(0.34, 1.4, 0.5, 1) 9100ms forwards;
    }
    .center-sublabel {
      opacity: 0;
      animation: labelRise 700ms cubic-bezier(0.22, 0.61, 0.36, 1) 9500ms forwards;
      transform-box: fill-box;
      transform-origin: center;
    }

    .pool-yes-win {
      opacity: 0;
      animation: winPulse 1600ms cubic-bezier(0.22, 0.61, 0.36, 1) 9400ms forwards;
    }
    .pool-yes-win rect {
      stroke: var(--pos);
      stroke-width: 2;
      fill: none;
    }

    @keyframes fadeIn            { from { opacity: 0; } to { opacity: 1; } }
    @keyframes fadeInBandBright  { from { opacity: 0; } to { opacity: 0.7; } }
    @keyframes fadeInBandFaded   { from { opacity: 0; } to { opacity: 0.55; } }
    @keyframes fadeInFaded       { from { opacity: 0; } to { opacity: 0.75; } }
    @keyframes maskGrow          { to { stroke-dashoffset: 0; } }
    @keyframes drawIn            { to { stroke-dashoffset: 0; } }
    @keyframes summonGlow {
      0%   { opacity: 0; transform: scale(1); }
      25%  { opacity: 0.45; transform: scale(1.02); }
      100% { opacity: 0; transform: scale(1.08); }
    }
    @keyframes labelPop {
      0%   { opacity: 0; transform: scale(0.86); }
      60%  { opacity: 1; transform: scale(1.04); }
      100% { opacity: 1; transform: scale(1); }
    }
    @keyframes labelRise {
      0%   { opacity: 0; transform: translateY(8px); }
      100% { opacity: 1; transform: translateY(0); }
    }
    @keyframes winPulse {
      0%   { opacity: 0; }
      30%  { opacity: 1; }
      100% { opacity: 0.7; }
    }

    @media (prefers-reduced-motion: reduce) {
      * { animation-duration: 0.01ms !important; animation-delay: 0ms !important; }
      .reveal-mask { stroke-dashoffset: 0; }
      .app-side-left, .app-side-right { opacity: 0.75; }
      .layer-band-apps, .layer-band-resolve { opacity: 0.55; }
      .layer-band-trade { opacity: 0.7; }
      .center-edge { stroke-dashoffset: 0; }
      .center-fill { opacity: 1; }
      .center-glow { opacity: 0; }
      .bet { opacity: 0; }
      .clock-flash, .settle-flash { opacity: 0; }
      .resolve-text-pre  { opacity: 0; }
      .resolve-text-post { opacity: 1; }
      .yes-p1, .yes-p2, .yes-p3, .yes-p4, .yes-p5,
      .no-p1,  .no-p2,  .no-p3,  .no-p4,  .no-p5,
      .yes-sub-cond, .no-sub-cond { opacity: 0; }
      .yes-payout, .no-payout, .yes-sub-math, .no-sub-math { opacity: 1; }
      .pool-yes-win { opacity: 0.7; }
      .pool-no-content { opacity: 0.32; }
    }
